@app.route('/mfa-setup', methods=['GET', 'POST'])
@login_required
def mfa_setup():
    """Endpoint for enabling MFA for a user."""
    if current_user.mfa_enabled:
        flash('MFA is already enabled for your account.', 'info')
        return redirect(url_for('dashboard'))

    if request.method == 'GET':
        # Generate a new random secret
        secret = pyotp.random_base32()
        # Store secret temporarily in session until the user confirms setup
        session['mfa_setup_secret'] = secret
        
        # Generate the provisioning URI for QR code generation
        # This URI can be used by authenticator apps to set up the TOTP token
        otp_uri = pyotp.totp.TOTP(secret).provisioning_uri(
            name=current_user.email,
            issuer_name="Flask MFA App" # Your application's name
        )
        # Use Google Charts API to generate a QR code image for demonstration
        # In production, consider generating QR codes locally or using a dedicated service.
        qr_code_url = f"https://chart.googleapis.com/chart?chs=200x200&chld=M|0&cht=qr&chl={urllib.parse.quote(otp_uri)}"
        
        return render_template('mfa_setup.html', secret=secret, otp_uri=otp_uri, qr_code_url=qr_code_url)

    if request.method == 'POST':
        mfa_code = request.form['mfa_code']
        temp_secret = session.get('mfa_setup_secret')

        if not temp_secret:
            flash('MFA setup session expired. Please start over.', 'danger')
            return redirect(url_for('mfa_setup'))

        totp = pyotp.TOTP(temp_secret)
        if totp.verify(mfa_code):
            # Code verified, save the secret and enable MFA
            current_user.mfa_secret = temp_secret
            current_user.mfa_enabled = True
            save_user(current_user)
            session.pop('mfa_setup_secret', None) # Clear temp secret from session
            flash('MFA enabled successfully!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid MFA code. Please try again.', 'danger')
            # If invalid, re-render the setup page with the same temporary secret
            otp_uri = pyotp.totp.TOTP(temp_secret).provisioning_uri(
                name=current_user.email,
                issuer_name="Flask MFA App"
            )
            qr_code_url = f"https://chart.googleapis.com/chart?chs=200x200&chld=M|0&cht=qr&chl={urllib.parse.quote(otp_uri)}"
            return render_template('mfa_setup.html', secret=temp_secret, otp_uri=otp_uri, qr_code_url=qr_code_url)

@app.route('/mfa-disable', methods=['GET', 'POST'])
@login_required
def mfa_disable():
    """Endpoint for disabling MFA for a user."""
    if not current_user.mfa_enabled:
        flash('MFA is not enabled for your account.', 'info')
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        password = request.form['password']
        mfa_code = request.form['mfa_code'] # Require current MFA code to disable

        if not check_password_hash(current_user.password_hash, password):
            flash('Invalid password.', 'danger')
            return render_template('mfa_disable.html')
        
        totp = pyotp.TOTP(current_user.mfa_secret)
        if not totp.verify(mfa_code):
            flash('Invalid MFA code. Cannot disable MFA without current valid code.', 'danger')
            return render_template('mfa_disable.html')

        # Both password and MFA code are correct, disable MFA
        current_user.mfa_secret = None
        current_user.mfa_enabled = False
        save_user(current_user)
        flash('MFA disabled successfully.', 'success')
        return redirect(url_for('dashboard'))
    
    return render_template('mfa_disable.html')

@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa_request():
    """
    Endpoint for requesting an MFA reset. Sends a secure, time-limited link to the user's email.
    """
    if request.method == 'POST':
        email = request.form['email'].lower()
        user_data = users.get(email)

        # Always provide a generic message to prevent email enumeration
        flash_message = 'If an account with that email exists, a MFA reset link has been sent to your email address.'

        if user_data:
            s = URLSafeTimedSerializer(current_app.config['SECRET_KEY'])
            # Generate a unique token for the user's email with a specific salt
            token = s.dumps(email, salt=current_app.config['MFA_RESET_TOKEN_SALT'])
            
            # Construct the full reset URL, _external=True generates a full URL
            reset_link = url_for('reset_mfa_confirm', token=token, _external=True)
            
            subject = "Multi-Factor Authentication (MFA) Reset Request"
            body = (f"Hello,\n\nYou requested to reset your Multi-Factor Authentication (MFA) "
                    f"settings for your account ({email}).\n\n"
                    f"Please click on the following link to disable MFA for your account: \n"
                    f"{reset_link}\n\n"
                    f"This link is valid for {current_app.config['MFA_RESET_TOKEN_EXPIRATION'] / 60} minutes.\n"
                    f"If you did not request this, please ignore this email.\n\n"
                    f"Regards,\nYour Flask MFA App Team")
            
            send_email(email, subject, body)
            flash(flash_message, 'info')
        else:
            flash(flash_message, 'info') # Generic message even if email not found
        
        return redirect(url_for('login'))
    
    return render_template('reset_mfa_request.html')

@app.route('/reset-mfa-confirm', methods=['GET'])
def reset_mfa_confirm():
    """
    Endpoint that processes the MFA reset link. Disables MFA for the user.
    """
    token = request.args.get('token')
    if not token:
        flash('MFA reset link is missing or invalid.', 'danger')
        return redirect(url_for('login'))

    s = URLSafeTimedSerializer(current_app.config['SECRET_KEY'])
    try:
        # Load the email from the token, verifying its signature and expiration
        email = s.loads(
            token,
            salt=current_app.config['MFA_RESET_TOKEN_SALT'],
            max_age=current_app.config['MFA_RESET_TOKEN_EXPIRATION']
        ).lower() # Ensure email is lowercase
    except SignatureExpired:
        flash('MFA reset link has expired. Please request a new one.', 'danger')
        return redirect(url_for('reset_mfa_request'))
    except BadTimeSignature:
        flash('MFA reset link is invalid or has been tampered with.', 'danger')
        return redirect(url_for('reset_mfa_request'))
    except Exception as e:
        flash(f'An error occurred: {e}', 'danger')
        return redirect(url_for('reset_mfa_request'))

    user_data = users.get(email)
    if user_data:
        user = User.from_dict(user_data)
        if user.mfa_enabled:
            # Disable MFA for the user
            user.mfa_enabled = False
            user.mfa_secret = None
            save_user(user)
            flash('Your Multi-Factor Authentication (MFA) settings have been reset. You can now log in with just your password.', 'success')
        else:
            flash('MFA was already disabled for your account. No changes were made.', 'info')
    else:
        # This case should ideally not happen if token was successfully loaded
        flash('User not found for the given reset link. Please try again or register.', 'danger')
    
    return redirect(url_for('login'))


