def create_templates(app):
    """
    Helper to create the template files in a 'templates' directory.
    This is necessary because Flask expects templates to be files, not strings.
    """
    template_dir = 'templates'
    if not os.path.exists(template_dir):
        os.makedirs(template_dir)
    
    templates = {
        'base.html': HTML_BASE,
        'register.html': HTML_REGISTER,
        'login.html': HTML_LOGIN,
        'login_mfa.html': HTML_LOGIN_MFA,
        'dashboard.html': HTML_DASHBOARD,
        'mfa_setup.html': HTML_MFA_SETUP,
        'mfa_disable.html': HTML_MFA_DISABLE,
        'reset_mfa_request.html': HTML_RESET_MFA_REQUEST,
    }

    for name, content in templates.items():
        with open(os.path.join(template_dir, name), 'w') as f:
            f.write(content)

# Ensure templates are created when the application starts
create_templates(app)

